package com.interview.lld.resourcepool.model;

// ── WHY THIS ENUM ──────────────────────────────────────────────────────────
// Resource lifecycle states — tracks whether a resource is available for borrowing
// or currently checked out.
// 🎙️ "Every resource is either free to acquire or in use by a client. This enum
// enforces that state so we never double-book."

public enum ResourceState {
    AVAILABLE,   // Resource is in the pool, ready to be acquired
    IN_USE       // Resource is checked out by a client
}

