package com.interview.lld.resourcepool.model;

import javax.annotation.Nullable;
import java.time.Instant;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Wrapper around the actual resource payload. Tracks state, checkout time,
// and owner thread. The pool manages these wrappers, not raw payloads.
// 🎙️ "This is the bookkeeping envelope around the real resource — like a library
// book wrapper that tracks who borrowed it and when."

public class PooledResource<T> implements AutoCloseable {
    private final String id;
    private final T payload;
    private ResourceState state;
    private Instant checkedOutAt;
    private Long ownerThreadId;

    public PooledResource(String id, T payload) {
        this.id = id;
        this.payload = payload;
        this.state = ResourceState.AVAILABLE;
        this.checkedOutAt = null;
        this.ownerThreadId = null;
    }

    // ── State Transitions ──────────────────────────────────────────────────
    // WHY: Only PooledResource changes its own state — the service never writes
    // state directly. This prevents illegal transitions.

    public void markInUse(Instant at, long threadId) {
        if (this.state != ResourceState.AVAILABLE) {
            throw new IllegalStateException(
                "Cannot check out resource " + id + " — already IN_USE"
            );
        }
        this.state = ResourceState.IN_USE;
        this.checkedOutAt = at;
        this.ownerThreadId = threadId;
    }

    public void markAvailable() {
        // WHY: Idempotent — calling this when already AVAILABLE is safe.
        // Prevents double-release errors when both a timeout sweep and explicit
        // return try to release the same resource.
        if (this.state == ResourceState.IN_USE) {
            this.state = ResourceState.AVAILABLE;
            this.checkedOutAt = null;
            this.ownerThreadId = null;
        }
    }

    // ── Getters ─────────────────────────────────────────────────────────────

    public String getId() {
        return id;
    }

    public T getPayload() {
        return payload;
    }

    public ResourceState getState() {
        return state;
    }

    @Nullable
    public Instant getCheckedOutAt() {
        return checkedOutAt;
    }

    @Nullable
    public Long getOwnerThreadId() {
        return ownerThreadId;
    }

    // ── AutoCloseable ───────────────────────────────────────────────────────
    // WHY: Allows try-with-resources pattern in client code:
    //      try (var res = pool.acquire(timeout)) { use(res.getPayload()); }
    // Resource auto-returns when the block exits.

    @Override
    public void close() {
        // This is a placeholder for the pool's return logic.
        // The actual pool service will override this behavior by wrapping
        // or the client explicitly calls pool.release(this).
        markAvailable();
    }

    @Override
    public String toString() {
        return String.format(
            "PooledResource{id='%s', state=%s, owner=%s}",
            id, state, ownerThreadId
        );
    }
}

