package com.interview.lld.resourcepool.service;

import com.interview.lld.resourcepool.model.*;

import javax.annotation.Nullable;
import java.time.Duration;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.Supplier;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// The orchestrator for the resource pool. Clean single-threaded core logic —
// no locks, no semaphores. Thread-safe version will extend this and override
// three Template Method hooks (gateLock, gateRelease, bookkeepingLock).
// 🎙️ "This is the brain. It manages the free list, creates resources lazily up to
// max_size, and blocks on a permit gate when exhausted. Zero lock code here —
// concurrency is in the subclass."

public class ResourcePoolService<T> {
    protected final int maxSize;
    protected final Supplier<T> factory;
    protected final List<PooledResource<T>> allResources;  // all created resources
    protected final List<PooledResource<T>> freeList;      // available resources (FIFO)
    protected final AtomicInteger nextId = new AtomicInteger(1);

    // WHY: Clock injection for testing — tests can fast-forward time without sleep.
    protected final Supplier<Instant> clock;

    public ResourcePoolService(int maxSize, Supplier<T> factory) {
        this(maxSize, factory, Instant::now);
    }

    public ResourcePoolService(int maxSize, Supplier<T> factory, Supplier<Instant> clock) {
        if (maxSize <= 0) {
            throw new IllegalArgumentException("maxSize must be positive");
        }
        this.maxSize = maxSize;
        this.factory = factory;
        this.clock = clock;
        this.allResources = new ArrayList<>(maxSize);
        this.freeList = new ArrayList<>(maxSize);
    }

    // ────────────────────────────────────────────────────────────────────────
    // PUBLIC API
    // ────────────────────────────────────────────────────────────────────────

    /**
     * Acquire a resource from the pool, blocking until one is available or timeout expires.
     *
     * @param timeout max wait duration; null means wait indefinitely
     * @return a PooledResource wrapper around the payload
     * @throws PoolExhaustedException if timeout expires before resource available
     */
    public PooledResource<T> acquire(@Nullable Duration timeout) {
        long deadlineNanos = (timeout != null)
            ? System.nanoTime() + timeout.toNanos()
            : Long.MAX_VALUE;

        // WHY: Semaphore gate OUTSIDE the bookkeeping lock. The permit blocks
        // when pool is at capacity; once acquired, we proceed to the fast
        // bookkeeping section.
        long remainingNanos = deadlineNanos - System.nanoTime();
        if (remainingNanos <= 0) {
            throw new PoolExhaustedException("Timeout expired before acquiring permit");
        }
        Duration remaining = Duration.ofNanos(remainingNanos);

        // WHY: Template Method hook — no-op in this class, real semaphore.tryAcquire
        // in thread-safe subclass.
        boolean acquired = gateLock(remaining);
        if (!acquired) {
            throw new PoolExhaustedException(
                "Pool exhausted — all " + maxSize + " resources in use, timeout " + timeout
            );
        }

        // WHY: Now we hold a permit. Lock the free list briefly to get or create a resource.
        PooledResource<T> resource = null;
        try {
            bookkeepingLock();
            try {
                resource = getOrCreateResource();
                resource.markInUse(clock.get(), Thread.currentThread().getId());
            } finally {
                bookkeepingUnlock();
            }
            return resource;
        } catch (Exception e) {
            // WHY: If we fail after acquiring the permit, release it so the semaphore
            // count stays correct.
            gateRelease();
            throw e;
        }
    }

    /**
     * Release a resource back to the pool.
     *
     * @param resource the resource to return
     * @throws InvalidResourceException if resource doesn't belong to this pool
     */
    public void release(PooledResource<T> resource) {
        bookkeepingLock();
        try {
            // WHY: Verify the resource belongs to this pool.
            if (!allResources.contains(resource)) {
                throw new InvalidResourceException(
                    "Resource " + resource.getId() + " does not belong to this pool"
                );
            }

            // WHY: Idempotent — calling release on an AVAILABLE resource is safe (no-op).
            if (resource.getState() == ResourceState.IN_USE) {
                resource.markAvailable();
                freeList.add(resource);  // FIFO: add to end
            }
        } finally {
            bookkeepingUnlock();
        }

        // WHY: Release the permit AFTER bookkeeping completes — this unblocks
        // a waiting acquire.
        gateRelease();
    }

    /**
     * Current count of in-use resources.
     */
    public int inUseCount() {
        bookkeepingLock();
        try {
            int count = 0;
            for (PooledResource<T> r : allResources) {
                if (r.getState() == ResourceState.IN_USE) {
                    count++;
                }
            }
            return count;
        } finally {
            bookkeepingUnlock();
        }
    }

    /**
     * Current count of available resources (created but not in use).
     */
    public int availableCount() {
        bookkeepingLock();
        try {
            return freeList.size();
        } finally {
            bookkeepingUnlock();
        }
    }

    /**
     * Total count of created resources (in-use + available).
     */
    public int totalCreated() {
        bookkeepingLock();
        try {
            return allResources.size();
        } finally {
            bookkeepingUnlock();
        }
    }

    // ────────────────────────────────────────────────────────────────────────
    // PRIVATE HELPERS
    // ────────────────────────────────────────────────────────────────────────

    /**
     * Get a resource from freeList or create a new one if under maxSize.
     * MUST be called under bookkeepingLock.
     */
    private PooledResource<T> getOrCreateResource() {
        // WHY: Prefer reuse over creation — if a resource is free, take it (FIFO).
        if (!freeList.isEmpty()) {
            return freeList.remove(0);  // FIFO: take from front
        }

        // WHY: Lazy creation — only create when freeList is empty and we haven't
        // hit maxSize. This defers resource cost until actually needed.
        if (allResources.size() < maxSize) {
            String id = "resource-" + nextId.getAndIncrement();
            T payload = factory.get();
            PooledResource<T> resource = new PooledResource<>(id, payload);
            allResources.add(resource);
            return resource;
        }

        // WHY: Should never reach here — the semaphore gate ensures we only enter
        // this section when a permit is available, meaning either freeList has an
        // entry or we can create a new one.
        throw new IllegalStateException("Semaphore logic error — no resource available");
    }

    // ────────────────────────────────────────────────────────────────────────
    // TEMPLATE METHOD HOOKS — no-op in this class, overridden by thread-safe subclass
    // ────────────────────────────────────────────────────────────────────────

    /**
     * Acquire the capacity gate permit. Blocks if pool is at capacity.
     * Returns true if acquired, false if timeout expired.
     *
     * WHY: No-op in the clean version. Thread-safe subclass overrides this with
     * semaphore.tryAcquire(timeout).
     */
    protected boolean gateLock(Duration timeout) {
        // No-op — single-threaded version has no gate
        return true;
    }

    /**
     * Release the capacity gate permit.
     *
     * WHY: No-op in the clean version. Thread-safe subclass overrides this with
     * semaphore.release().
     */
    protected void gateRelease() {
        // No-op — single-threaded version has no gate
    }

    /**
     * Lock for bookkeeping mutations (freeList, allResources, resource state).
     *
     * WHY: No-op in the clean version. Thread-safe subclass overrides this with
     * a mutex lock for the microsecond-scale bookkeeping section.
     */
    protected void bookkeepingLock() {
        // No-op — single-threaded version has no lock
    }

    /**
     * Unlock bookkeeping mutex.
     */
    protected void bookkeepingUnlock() {
        // No-op — single-threaded version has no lock
    }
}

