package com.interview.lld.resourcepool.service;

import java.time.Duration;
import java.time.Instant;
import java.util.concurrent.Semaphore;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.locks.ReentrantLock;
import java.util.function.Supplier;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Thread-safe version of ResourcePoolService. Overrides exactly THREE Template
// Method hooks to add concurrency control:
// 1. gateLock/gateRelease — counting Semaphore (initialized to maxSize)
// 2. bookkeepingLock/Unlock — ReentrantLock for fast mutations
//
// The base class logic stays IDENTICAL — this is pure concurrency layering.
// 🎙️ "The §9 version. Only three methods change — the rest is inherited verbatim.
// The semaphore blocks acquire when all permits are taken; the bookkeeping lock
// protects the free list for microseconds."

public class ThreadSafeResourcePoolService<T> extends ResourcePoolService<T> {
    private final Semaphore capacityGate;      // Permits = available capacity
    private final ReentrantLock bookkeepingMutex;  // Guards freeList/allResources mutations

    public ThreadSafeResourcePoolService(int maxSize, Supplier<T> factory) {
        this(maxSize, factory, Instant::now);
    }

    public ThreadSafeResourcePoolService(
        int maxSize,
        Supplier<T> factory,
        Supplier<Instant> clock
    ) {
        super(maxSize, factory, clock);
        // WHY: Semaphore initialized to maxSize — each permit represents one slot.
        // Fair=true ensures FIFO ordering for blocked threads.
        this.capacityGate = new Semaphore(maxSize, true);
        this.bookkeepingMutex = new ReentrantLock();
    }

    // ────────────────────────────────────────────────────────────────────────
    // TEMPLATE METHOD OVERRIDES — the ONLY difference from base class
    // ────────────────────────────────────────────────────────────────────────

    @Override
    protected boolean gateLock(Duration timeout) {
        // WHY: Try to acquire one permit. If all maxSize resources are in use,
        // this blocks until one is released or timeout expires.
        try {
            if (timeout.toNanos() == Long.MAX_VALUE) {
                capacityGate.acquire();
                return true;
            } else {
                return capacityGate.tryAcquire(timeout.toNanos(), TimeUnit.NANOSECONDS);
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return false;
        }
    }

    @Override
    protected void gateRelease() {
        // WHY: Release one permit back to the semaphore — unblocks a waiting acquire.
        capacityGate.release();
    }

    @Override
    protected void bookkeepingLock() {
        // WHY: Acquire the mutex before touching freeList or allResources.
        // This section is microseconds — just list add/remove, no IO.
        bookkeepingMutex.lock();
    }

    @Override
    protected void bookkeepingUnlock() {
        bookkeepingMutex.unlock();
    }
}

