package com.interview.lld.resourcepool;

import com.interview.lld.resourcepool.model.PooledResource;
import com.interview.lld.resourcepool.model.PoolExhaustedException;
import com.interview.lld.resourcepool.service.ThreadSafeResourcePoolService;

import java.time.Duration;
import java.util.concurrent.atomic.AtomicInteger;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Demo driver exercising the resource pool with 5 cases:
// 1. Happy path: acquire + release
// 2. Lazy creation: first 3 acquires create resources on demand
// 3. Exhaustion: 4th acquire with short timeout fails
// 4. FIFO reuse: after releases, acquires reuse resources in order
// 5. Concurrency: multiple threads race for limited capacity
//
// 🎙️ "This proves the pool works — lazy creation, blocking on exhaustion, fair
// FIFO ordering, and strict capacity under load."

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Resource Pool Demo ===\n");

        // Case 1: Happy path — acquire and release
        {
            System.out.println("Case 1: Happy path acquire/release");
            var pool = new ThreadSafeResourcePoolService<>(
                3,
                () -> new MockDBConnection(nextConnId.getAndIncrement())
            );
            try {
                var res = pool.acquire(Duration.ofSeconds(1));
                System.out.println("  Acquired: " + res.getId() + ", payload=" + res.getPayload());
                pool.release(res);
                System.out.println("  Released: " + res.getId());
                System.out.println("  totalCreated=" + pool.totalCreated() + ", available=" + pool.availableCount());
                System.out.println("  → Case 1 OK\n");
            } catch (Exception e) {
                System.out.println("  FAIL: " + e.getMessage());
            }
        }

        // Case 2: Lazy creation — resources created on demand
        {
            System.out.println("Case 2: Lazy creation up to maxSize=3");
            var pool = new ThreadSafeResourcePoolService<>(
                3,
                () -> new MockDBConnection(nextConnId.getAndIncrement())
            );
            try {
                var r1 = pool.acquire(Duration.ofSeconds(1));
                System.out.println("  Acquired r1: totalCreated=" + pool.totalCreated());
                var r2 = pool.acquire(Duration.ofSeconds(1));
                System.out.println("  Acquired r2: totalCreated=" + pool.totalCreated());
                var r3 = pool.acquire(Duration.ofSeconds(1));
                System.out.println("  Acquired r3: totalCreated=" + pool.totalCreated());

                pool.release(r1);
                pool.release(r2);
                pool.release(r3);
                System.out.println("  All released: inUse=" + pool.inUseCount() + ", available=" + pool.availableCount());
                System.out.println("  → Case 2 OK\n");
            } catch (Exception e) {
                System.out.println("  FAIL: " + e.getMessage());
            }
        }

        // Case 3: Exhaustion — acquire fails when pool is full
        {
            System.out.println("Case 3: Pool exhaustion with timeout");
            var pool = new ThreadSafeResourcePoolService<>(
                2,
                () -> new MockDBConnection(nextConnId.getAndIncrement())
            );
            try {
                var r1 = pool.acquire(Duration.ofSeconds(1));
                var r2 = pool.acquire(Duration.ofSeconds(1));
                System.out.println("  Acquired 2 resources (pool full)");

                // This should timeout immediately
                try {
                    pool.acquire(Duration.ofMillis(50));
                    System.out.println("  FAIL: should have thrown PoolExhaustedException");
                } catch (PoolExhaustedException e) {
                    System.out.println("  Expected exhaustion: " + e.getMessage());
                    System.out.println("  → Case 3 OK\n");
                }

                pool.release(r1);
                pool.release(r2);
            } catch (Exception e) {
                System.out.println("  FAIL: " + e.getMessage());
            }
        }

        // Case 4: FIFO reuse — released resources returned in FIFO order
        {
            System.out.println("Case 4: FIFO reuse order");
            var pool = new ThreadSafeResourcePoolService<>(
                3,
                () -> new MockDBConnection(nextConnId.getAndIncrement())
            );
            try {
                var r1 = pool.acquire(null);
                var r2 = pool.acquire(null);
                String id1 = r1.getId();
                String id2 = r2.getId();
                System.out.println("  First wave: acquired " + id1 + ", " + id2);

                pool.release(r1);  // Released first
                pool.release(r2);  // Released second
                System.out.println("  Released in order: " + id1 + " then " + id2);

                var r3 = pool.acquire(null);
                var r4 = pool.acquire(null);
                System.out.println("  Second wave: acquired " + r3.getId() + ", " + r4.getId());

                if (r3.getId().equals(id1) && r4.getId().equals(id2)) {
                    System.out.println("  FIFO confirmed — reused in release order");
                    System.out.println("  → Case 4 OK\n");
                } else {
                    System.out.println("  FAIL: FIFO broken");
                }

                pool.release(r3);
                pool.release(r4);
            } catch (Exception e) {
                System.out.println("  FAIL: " + e.getMessage());
            }
        }

        // Case 5: Concurrency — 20 threads compete for 5 resources
        {
            System.out.println("Case 5: Concurrency — 20 threads, 5 capacity");
            var pool = new ThreadSafeResourcePoolService<>(
                5,
                () -> new MockDBConnection(nextConnId.getAndIncrement())
            );

            AtomicInteger succeeded = new AtomicInteger(0);
            AtomicInteger failed = new AtomicInteger(0);

            Thread[] threads = new Thread[20];
            for (int i = 0; i < 20; i++) {
                final int idx = i;
                threads[i] = new Thread(() -> {
                    try {
                        var res = pool.acquire(Duration.ofSeconds(3));
                        succeeded.incrementAndGet();
                        Thread.sleep(50);  // Hold briefly to force concurrency
                        pool.release(res);
                    } catch (PoolExhaustedException e) {
                        failed.incrementAndGet();
                    } catch (Exception e) {
                        System.out.println("  Unexpected error in thread " + idx + ": " + e);
                    }
                });
                threads[i].start();
            }

            for (Thread t : threads) {
                try {
                    t.join();
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            }

            System.out.println("  Threads completed: succeeded=" + succeeded.get() + ", failed=" + failed.get());
            System.out.println("  Final state: totalCreated=" + pool.totalCreated() + ", inUse=" + pool.inUseCount());

            if (succeeded.get() == 20 && pool.totalCreated() <= 5 && pool.inUseCount() == 0) {
                System.out.println("  All threads served, capacity respected, all released");
                System.out.println("  → Case 5 OK\n");
            } else {
                System.out.println("  FAIL: concurrency invariants violated");
            }
        }

        System.out.println("=== All cases passed ===");
    }

    // ── Mock Resource ───────────────────────────────────────────────────────
    private static final AtomicInteger nextConnId = new AtomicInteger(1);

    static class MockDBConnection {
        private final int id;

        MockDBConnection(int id) {
            this.id = id;
        }

        @Override
        public String toString() {
            return "DBConn#" + id;
        }
    }
}

