package com.interview.lld.resourcepool;

import com.interview.lld.resourcepool.model.InvalidResourceException;
import com.interview.lld.resourcepool.model.PooledResource;
import com.interview.lld.resourcepool.model.PoolExhaustedException;
import com.interview.lld.resourcepool.model.ResourceState;
import com.interview.lld.resourcepool.service.ThreadSafeResourcePoolService;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.time.Duration;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

class ResourcePoolServiceTest {

    // ── Happy Path Tests ────────────────────────────────────────────────────

    @Test
    void testAcquireAndRelease() {
        var pool = new ThreadSafeResourcePoolService<>(5, () -> "resource");
        var res = pool.acquire(Duration.ofSeconds(1));

        assertNotNull(res);
        assertEquals(ResourceState.IN_USE, res.getState());
        assertEquals(1, pool.inUseCount());
        assertEquals(1, pool.totalCreated());

        pool.release(res);
        assertEquals(ResourceState.AVAILABLE, res.getState());
        assertEquals(0, pool.inUseCount());
        assertEquals(1, pool.availableCount());
    }

    @Test
    void testLazyCreation() {
        var counter = new AtomicInteger(0);
        var pool = new ThreadSafeResourcePoolService<>(
            3,
            () -> "conn-" + counter.incrementAndGet()
        );

        assertEquals(0, pool.totalCreated(), "No resources created initially");

        var r1 = pool.acquire(null);
        assertEquals(1, pool.totalCreated());

        var r2 = pool.acquire(null);
        assertEquals(2, pool.totalCreated());

        var r3 = pool.acquire(null);
        assertEquals(3, pool.totalCreated());

        pool.release(r1);
        pool.release(r2);
        pool.release(r3);

        // No new resource created — reuse existing
        var r4 = pool.acquire(null);
        assertEquals(3, pool.totalCreated(), "Should reuse, not create new");

        pool.release(r4);
    }

    @Test
    void testFifoOrdering() {
        var pool = new ThreadSafeResourcePoolService<>(3, () -> UUID.randomUUID().toString());

        var r1 = pool.acquire(null);
        var r2 = pool.acquire(null);
        String id1 = r1.getId();
        String id2 = r2.getId();

        pool.release(r1);  // Released first
        pool.release(r2);  // Released second

        var r3 = pool.acquire(null);
        var r4 = pool.acquire(null);

        assertEquals(id1, r3.getId(), "First released should be first reused (FIFO)");
        assertEquals(id2, r4.getId(), "Second released should be second reused (FIFO)");

        pool.release(r3);
        pool.release(r4);
    }

    // ── Exhaustion & Timeout Tests ──────────────────────────────────────────

    @Test
    void testPoolExhaustion() {
        var pool = new ThreadSafeResourcePoolService<>(2, () -> "resource");

        var r1 = pool.acquire(Duration.ofSeconds(1));
        var r2 = pool.acquire(Duration.ofSeconds(1));

        // Pool is full — next acquire should timeout
        assertThrows(PoolExhaustedException.class, () ->
            pool.acquire(Duration.ofMillis(50))
        );

        pool.release(r1);
        pool.release(r2);
    }

    @Test
    void testAcquireWithNullTimeout() {
        var pool = new ThreadSafeResourcePoolService<>(1, () -> "resource");
        var r1 = pool.acquire(null);  // null = wait indefinitely

        assertNotNull(r1);
        pool.release(r1);
    }

    @Test
    void testAcquireBlocksUntilAvailable() throws Exception {
        var pool = new ThreadSafeResourcePoolService<>(1, () -> "resource");
        var r1 = pool.acquire(Duration.ofSeconds(5));

        CompletableFuture<PooledResource<String>> future = CompletableFuture.supplyAsync(() -> {
            try {
                Thread.sleep(200);  // Wait before releasing
                pool.release(r1);
                return null;
            } catch (Exception e) {
                throw new RuntimeException(e);
            }
        });

        long start = System.currentTimeMillis();
        var r2 = pool.acquire(Duration.ofSeconds(5));  // Should block ~200ms
        long elapsed = System.currentTimeMillis() - start;

        assertNotNull(r2);
        assertTrue(elapsed >= 150, "Should have blocked until r1 released");
        assertEquals(r1.getId(), r2.getId(), "Should reuse the same resource");

        pool.release(r2);
        future.get();
    }

    // ── Invalid Input Tests ─────────────────────────────────────────────────

    @Test
    void testInvalidMaxSize() {
        assertThrows(IllegalArgumentException.class, () ->
            new ThreadSafeResourcePoolService<>(0, () -> "resource")
        );

        assertThrows(IllegalArgumentException.class, () ->
            new ThreadSafeResourcePoolService<>(-1, () -> "resource")
        );
    }

    @Test
    void testReleaseUnknownResource() {
        var pool1 = new ThreadSafeResourcePoolService<>(2, () -> "resource");
        var pool2 = new ThreadSafeResourcePoolService<>(2, () -> "resource");

        var r1 = pool1.acquire(null);

        // Trying to release r1 to pool2 should fail
        assertThrows(InvalidResourceException.class, () ->
            pool2.release(r1)
        );

        pool1.release(r1);
    }

    // ── Idempotency Tests ───────────────────────────────────────────────────

    @Test
    void testIdempotentRelease() {
        var pool = new ThreadSafeResourcePoolService<>(2, () -> "resource");
        var r1 = pool.acquire(null);

        pool.release(r1);
        assertEquals(ResourceState.AVAILABLE, r1.getState());
        assertEquals(1, pool.availableCount());

        // Second release is a no-op (idempotent)
        pool.release(r1);
        assertEquals(ResourceState.AVAILABLE, r1.getState());
        assertEquals(1, pool.availableCount(), "Double release should not duplicate in freeList");
    }

    // ── Concurrency Tests (STRICT) ──────────────────────────────────────────

    @Test
    void testConcurrentAcquireStrictCapacity() throws Exception {
        int N = 50;  // threads
        int CAP = 5; // capacity

        var pool = new ThreadSafeResourcePoolService<>(CAP, () -> UUID.randomUUID().toString());

        CyclicBarrier barrier = new CyclicBarrier(N);
        AtomicInteger served = new AtomicInteger(0);
        AtomicInteger peakInUse = new AtomicInteger(0);
        Set<String> distinctResourceIds = ConcurrentHashMap.newKeySet();
        List<Exception> errors = Collections.synchronizedList(new ArrayList<>());

        ExecutorService executor = Executors.newFixedThreadPool(N);

        for (int i = 0; i < N; i++) {
            executor.submit(() -> {
                try {
                    barrier.await();  // All threads start together (stampede)

                    var res = pool.acquire(Duration.ofSeconds(10));
                    served.incrementAndGet();
                    distinctResourceIds.add(res.getId());

                    // Track peak usage
                    int current = pool.inUseCount();
                    peakInUse.updateAndGet(p -> Math.max(p, current));

                    // Assert capacity never breached
                    assertTrue(current <= CAP, "Capacity breached: inUse=" + current + " > " + CAP);

                    Thread.sleep(20);  // Hold to force genuine concurrency
                    pool.release(res);

                } catch (Exception e) {
                    errors.add(e);
                }
            });
        }

        executor.shutdown();
        assertTrue(executor.awaitTermination(15, TimeUnit.SECONDS), "Threads did not complete");

        // Strict assertions
        assertEquals(N, served.get(), "All threads should be served");
        assertEquals(CAP, peakInUse.get(), "Peak usage should hit exactly maxSize");
        assertTrue(distinctResourceIds.size() <= CAP, "Should not create more than CAP resources");
        assertEquals(0, pool.inUseCount(), "All resources should be released");
        assertEquals(0, errors.size(), "No unexpected errors");
    }

    @Test
    void testConcurrentAcquireWithTimeout() throws Exception {
        int N = 20;
        int CAP = 3;

        var pool = new ThreadSafeResourcePoolService<>(CAP, () -> "resource");

        CyclicBarrier barrier = new CyclicBarrier(N);
        AtomicInteger succeeded = new AtomicInteger(0);
        AtomicInteger timedOut = new AtomicInteger(0);

        ExecutorService executor = Executors.newFixedThreadPool(N);

        for (int i = 0; i < N; i++) {
            executor.submit(() -> {
                try {
                    barrier.await();

                    var res = pool.acquire(Duration.ofMillis(100));
                    succeeded.incrementAndGet();
                    Thread.sleep(50);
                    pool.release(res);

                } catch (PoolExhaustedException e) {
                    timedOut.incrementAndGet();
                } catch (Exception e) {
                    fail("Unexpected error: " + e);
                }
            });
        }

        executor.shutdown();
        assertTrue(executor.awaitTermination(5, TimeUnit.SECONDS));

        // With short timeout and high contention, some should timeout
        assertTrue(succeeded.get() >= CAP, "At least CAP threads should succeed");
        assertTrue(timedOut.get() > 0, "Some threads should timeout due to contention");
        assertEquals(N, succeeded.get() + timedOut.get(), "All threads accounted for");
    }

    @Test
    void testNoDoubleBooking() throws Exception {
        int N = 100;
        int CAP = 10;

        var pool = new ThreadSafeResourcePoolService<>(CAP, () -> UUID.randomUUID().toString());

        CyclicBarrier barrier = new CyclicBarrier(N);
        Set<String> activeResources = ConcurrentHashMap.newKeySet();
        AtomicInteger maxConcurrent = new AtomicInteger(0);
        AtomicInteger collisions = new AtomicInteger(0);

        ExecutorService executor = Executors.newFixedThreadPool(N);

        for (int i = 0; i < N; i++) {
            executor.submit(() -> {
                try {
                    barrier.await();

                    var res = pool.acquire(Duration.ofSeconds(10));
                    String id = res.getId();

                    // Try to add to active set — if already there, it's double-booked
                    boolean added = activeResources.add(id);
                    if (!added) {
                        collisions.incrementAndGet();
                    }

                    maxConcurrent.updateAndGet(m -> Math.max(m, activeResources.size()));

                    Thread.sleep(10);

                    activeResources.remove(id);
                    pool.release(res);

                } catch (Exception e) {
                    // Expected for threads beyond capacity
                }
            });
        }

        executor.shutdown();
        assertTrue(executor.awaitTermination(15, TimeUnit.SECONDS));

        assertEquals(0, collisions.get(), "No resource should be double-booked");
        assertTrue(maxConcurrent.get() <= CAP, "Max concurrent should not exceed capacity");
    }

    // ── Clock Injection Test ────────────────────────────────────────────────

    @Test
    void testClockInjection() {
        AtomicInteger clockCalls = new AtomicInteger(0);
        Instant fixedTime = Instant.parse("2026-06-21T10:00:00Z");

        var pool = new ThreadSafeResourcePoolService<>(
            2,
            () -> "resource",
            () -> {
                clockCalls.incrementAndGet();
                return fixedTime;
            }
        );

        var res = pool.acquire(null);
        assertEquals(fixedTime, res.getCheckedOutAt(), "Should use injected clock");
        assertTrue(clockCalls.get() > 0, "Clock should have been called");

        pool.release(res);
    }
}

